package entity_test

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchE4ED83FE(t *testing.T) {
	const epsilon = 1e-9

	tests := []struct {
		name  string
		order entity.Order
		want  float64
	}{
		{
			name:  "empty items",
			order: entity.Order{},
			want:  0,
		},
		{
			name: "zero quantity",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 0, Price: 10.0},
				},
			},
			want: 0,
		},
		{
			name: "negative price",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 2, Price: -5.0},
				},
			},
			want: -10.0,
		},
		{
			name: "large quantity",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 1_000_000, Price: 0.99},
				},
			},
			want: 990000.0,
		},
		{
			name: "mixed positive, zero, negative",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 3, Price: 4.5},   // 13.5
					{Quantity: 0, Price: 100.0}, // 0
					{Quantity: 2, Price: -2.0},  // -4
				},
			},
			want: 9.5,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			got := tt.order.CalculateTotal()
			if math.Abs(got-tt.want) > epsilon {
				t.Fatalf("CalculateTotal() = %v, want %v", got, tt.want)
			}
		})
	}
}

