package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench349B1AE5(t *testing.T) {
	tests := []struct {
		name   string
		status entity.OrderStatus
		want   bool
	}{
		{
			name:   "Pending",
			status: entity.OrderStatusPending,
			want:   true,
		},
		{
			name:   "Processing",
			status: entity.OrderStatusProcessing,
			want:   true,
		},
		{
			name:   "Completed",
			status: entity.OrderStatusCompleted,
			want:   false,
		},
		{
			name:   "Cancelled",
			status: entity.OrderStatusCancelled,
			want:   false,
		},
		{
			name:   "ZeroValue",
			status: entity.OrderStatus(0),
			want:   false,
		},
		{
			name:   "Unknown",
			status: entity.OrderStatus(999),
			want:   false,
		},
	}

	for _, tt := range tests {
		tt := tt
		t.Run(tt.name, func(t *testing.T) {
			o := entity.Order{Status: tt.status}
			if got := o.CanCancel(); got != tt.want {
				t.Fatalf("expected %v, got %v", tt.want, got)
			}
		})
	}
}

