package entity_test

// CHOICE: Product.ApplyDiscount — edge cases for out‑of‑range discounts not covered
import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchF308E8AF(t *testing.T) {
	type testCase struct {
		name       string
		discount   float64
		wantPrice  float64
		wantErr    bool
	}
	basePrice := 100.0

	tests := []testCase{
		{
			name:      "zero discount",
			discount:  0,
			wantPrice: basePrice,
			wantErr:   false,
		},
		{
			name:      "full discount 100%",
			discount:  100,
			wantPrice: 0,
			wantErr:   false,
		},
		{
			name:      "normal discount 25%",
			discount:  25,
			wantPrice: basePrice * 0.75,
			wantErr:   false,
		},
		{
			name:      "negative discount (invalid)",
			discount:  -10,
			wantPrice: basePrice,
			wantErr:   true,
		},
		{
			name:      "over 100% discount (invalid)",
			discount:  150,
			wantPrice: basePrice,
			wantErr:   true,
		},
	}

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			// arrange
			p := entity.Product{
				ID:    1,
				Name:  "Test Coffee",
				Price: basePrice,
			}

			// act
			err := p.ApplyDiscount(tc.discount)

			// assert error expectation
			if (err != nil) != tc.wantErr {
				t.Fatalf("ApplyDiscount(%v) error = %v, wantErr %v", tc.discount, err, tc.wantErr)
			}

			// if no error expected, verify price
			if !tc.wantErr && p.Price != tc.wantPrice {
				t.Fatalf("ApplyDiscount(%v) resulted price = %v, want %v", tc.discount, p.Price, tc.wantPrice)
			}
		})
	}
}
